1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	export interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	export interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	export type Step = QuoteStep | ClaimStep;
25	
26	export interface Scenario {
27	  customer: Customer;
28	  steps: Step[];
29	}
30	
31	type Customer = { yearsWithMHPCO: number };
32	
33	export interface QuoteResult { premium: number }
34	export interface ClaimResult { payout: number; remainingCap: number }
35	
36	export interface ScenarioResult {
37	  results: (QuoteResult | ClaimResult)[];
38	}
39	
40	const PROCESSING_FEE = 5;
41	
42	const BASE_PRICE_BY_TYPE: Record<string, number> = {
43	  sword: 100,
44	  amulet: 60,
45	  staff: 80,
46	  potion: 40,
47	  rune: 25,
48	  moonstone: 25,
49	};
50	
51	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
52	  sword: 1000,
53	  amulet: 600,
54	  staff: 800,
55	  potion: 400,
56	  rune: 250,
57	  moonstone: 250,
58	};
59	
60	const DEDUCTIBLE = 100;
61	const CAP_MULTIPLIER = 2;
62	
63	const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
64	
65	const COMPONENT_BLOCK_SIZE = 3;
66	const COMPONENT_BLOCK_PRICE = 60;
67	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
68	
69	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
70	
71	const sumBasePrices = (items: Item[]): number =>
72	  items.reduce((s, i) => s + basePriceFor(i), 0);
73	
74	const groupByType = (items: Item[]): Map<string, Item[]> => {
75	  const map = new Map<string, Item[]>();
76	  for (const item of items) {
77	    const list = map.get(item.type) ?? [];
78	    list.push(item);
79	    map.set(item.type, list);
80	  }
81	  return map;
82	};
83	
84	const priceForComponentGroup = (group: Item[]): number =>
85	  group.length === COMPONENT_BLOCK_SIZE
86	    ? COMPONENT_BLOCK_PRICE
87	    : sumBasePrices(group);
88	
89	const componentsPremium = (components: Item[]): number =>
90	  Array.from(groupByType(components).values())
91	    .reduce((sum, group) => sum + priceForComponentGroup(group), 0);
92	
93	const itemsBasePremium = (items: Item[]): number => {
94	  const components = items.filter(isComponent);
95	  const nonComponents = items.filter((i) => !isComponent(i));
96	  return sumBasePrices(nonComponents) + componentsPremium(components);
97	};
98	
99	const CURSE_SURCHARGE_RATE = 0.5;
100	const HIGH_ENCHANTMENT_RATE = 0.3;
101	const HIGH_ENCHANTMENT_THRESHOLD = 5;
102	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
103	const LOYALTY_DISCOUNT_RATE = 0.2;
104	const LOYALTY_YEARS_THRESHOLD = 2;
105	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
106	
107	const perItemSurchargeRate = (item: Item): number =>
108	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
109	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0);
110	
111	const itemSurcharges = (items: Item[]): number =>
112	  items.reduce((sum, item) => sum + basePriceFor(item) * perItemSurchargeRate(item), 0);
113	
114	const isLoyal = (customer: Customer): boolean =>
115	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
116	
117	const loyaltyDiscountFor = (base: number, customer: Customer): number =>
118	  isLoyal(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
119	
120	const followUpDiscountFor = (base: number, isFollowUp: boolean): number =>
121	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
122	
123	const quotePremium = (step: QuoteStep, customer: Customer, isFollowUp: boolean): number => {
124	  const base = itemsBasePremium(step.items);
125	  const total = base
126	    + itemSurcharges(step.items)
127	    + base * FIRST_INSURANCE_SURCHARGE_RATE
128	    - loyaltyDiscountFor(base, customer)
129	    - followUpDiscountFor(base, isFollowUp);
130	  return Math.ceil(total + PROCESSING_FEE);
131	};
132	
133	type Policy = { items: Item[]; remainingCap: number };
134	
135	const insuranceSum = (items: Item[]): number =>
136	  items.reduce((s, i) => s + INSURANCE_VALUE_BY_TYPE[i.type], 0);
137	
138	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
139	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
140	
141	const reimbursableFor = (damage: Damage, item: Item): number => {
142	  const isHighEnchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
143	  const damageAmount = isHighEnchantment
144	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
145	    : damage.amount;
146	  const insured = Math.min(damageAmount, INSURANCE_VALUE_BY_TYPE[damage.itemType]);
147	  return Math.max(0, insured - DEDUCTIBLE);
148	};
149	
150	const findPolicyItem = (items: Item[], itemType: string): Item =>
151	  items.find((i) => i.type === itemType)!;
152	
153	const totalPayoutWithinCap = (damages: Damage[], items: Item[], cap: number): number =>
154	  damages.reduce(
155	    (paid, damage) =>
156	      paid + Math.min(reimbursableFor(damage, findPolicyItem(items, damage.itemType)), cap - paid),
157	    0,
158	  );
159	
160	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
161	  const policy = policies[step.policy];
162	  const payout = totalPayoutWithinCap(step.incident.damages, policy.items, policy.remainingCap);
163	  policy.remainingCap -= payout;
164	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
165	};
166	
167	export const runScenario = (scenario: Scenario): ScenarioResult => {
168	  const policies: Policy[] = [];
169	  const results: (QuoteResult | ClaimResult)[] = [];
170	  scenario.steps.forEach((step, i) => {
171	    if (step.op === "quote") {
172	      policies[i] = {
173	        items: step.items,
174	        remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
175	      };
176	      results.push({ premium: quotePremium(step, scenario.customer, i > 0) });
177	    } else {
178	      results.push(processClaim(step, policies));
179	    }
180	  });
181	  return { results };
182	};
